import { makeStyles } from '@material-ui/core'
import React from 'react'

const useStyle = makeStyles(theme => ({
    page: {
        background: '#f9fbfd',
        width: '100%'
    }
}));

export default function Layout({children}) {
    const classes = useStyle()

  return (
// appbar

// sidebar

    <div>
        <div className={classes.page}>
            {children}
        </div>
    </div>
  )
}
